def factorize(n: int) -> List[int]:
    factors = []
    if n <= 1:
        return factors
    # Handle factor 2 separately
    while n % 2 == 0:
        factors.append(2)
        n //= 2
    # Check odd factors from 3 onwards
    i = 3
    while i * i <= n:
        while n % i == 0:
            factors.append(i)
            n //= i
        i += 2
    # If n is a prime number greater than 2
    if n > 2:
        factors.append(n)
    return factors

def factorize(n: int) -> List[int]:
    if n == 0 or n == 1 or n == -1:
        return []
    factors = []
    abs_n = abs(n)
    # Factor out 2s
    while abs_n % 2 == 0:
        factors.append(2)
        abs_n //= 2
    # Factor out odd numbers
    d = 3
    while d * d <= abs_n:
        while abs_n % d == 0:
            factors.append(d)
            abs_n //= d
        d += 2
    # If remaining is a prime > 2
    if abs_n > 1:
        factors.append(abs_n)
    return factors

