def smallest_change(arr):
    import sys
    n = len(arr)
    arr_sorted = sorted(arr)
    index_map = {val: i for i, val in enumerate(arr_sorted)}
    visited = [False] * n
    ans = 0
    for i in range(n // 2):
        if arr[i] == arr_sorted[i] or visited[i]:
            continue
        j = i
        cycle_size = 0
        while not visited[j]:
            visited[j] = True
            j = index_map[arr[j]]
            cycle_size += 1
        if cycle_size > 0:
            ans += (cycle_size - 1) // 2
    return ans

