def fix_spaces(text):
    import re
    # Replace sequences of 3 or more spaces with hyphen, then sequences of 2 spaces with underscore
    # But to distinguish between 2 and >=3, we use a regex with a capturing group
    def repl(match):
        if len(match.group(0)) >= 3:
            return '-'
        else:
            return '_'
    # First, split the text into runs of spaces and non-spaces
    # But using regex substitution with a function is easier
    # We'll use a regex to match 2 or more spaces, and check their length inside the function
    import re
    def replace_spaces(match):
        s = match.group(0)
        if len(s) >= 3:
            return '-'
        else:
            return '_'
    # We need to process all space sequences, but keep non-space parts untouched
    # So we can use re.sub with a function that examines the matched space string
    result = []
    i = 0
    n = len(text)
    while i < n:
        if text[i] == ' ':
            start = i
            while i < n and text[i] == ' ':
                i += 1
            end = i
            space_len = end - start
            if space_len >= 3:
                result.append('-')
            elif space_len == 2:
                result.append('_')
            else:
                result.append(' ')
        else:
            result.append(text[i])
            i += 1
    return ''.join(result)

