def triples_sum_to_zero(l: list):
    """
    Returns True if there exists a triplet in the list that sums to zero.
    """
    n = len(l)
    if n < 3:
        return False
    l_sorted = sorted(l)
    for i in range(n - 2):
        if i > 0 and l_sorted[i] == l_sorted[i - 1]:
            continue
        left, right = i + 1, n - 1
        while left < right:
            s = l_sorted[i] + l_sorted[left] + l_sorted[right]
            if s == 0:
                return True
            elif s < 0:
                left += 1
            else:
                right -= 1
    return False

